let numero = local('%numerito');

// Si no existe, inicializarlo en 1
if (!numero) {
    numero = 1;
} else {
    // Convertir el valor obtenido del almacenamiento local a un número
    numero = parseInt(numero);
}

function generarNumero() {

numero++;
    let numeroFormateado = numero.toString().padStart(3, '0');



setLocal('%new_numerito', numeroFormateado);
}
generarNumero();

function generarCodigo() {
    var codigo = '';
    var caracteres = 'abcdefghijklmnopqrstuvwxyz'; 
    var numeros = '0123456789'; 

    for (var i = 0; i < 5; i++) {
        codigo += caracteres.charAt(Math.floor(Math.random() * caracteres.length));
    }

    for (var i = 0; i < 5; i++) {
        codigo += numeros.charAt(Math.floor(Math.random() * numeros.length));
    }

    codigo = codigo.split('').sort(function(){return 0.5-Math.random()}).join('');

    return codigo;
}


var codigoGenerado = generarCodigo();
setLocal('%code', codigoGenerado);

var date = local('%asjson');
var datos = JSON.parse(date);

function buscarPorTelefonoYColumna(telefono, columna) {
    const cabecera = obtenerCabecera();

    for (let i = 0; i < datos.length; i++) {
        if (datos[i][columna] === telefono) {
            const resultado = {};
            cabecera.forEach((cabeceraItem, index) => {
                resultado[cabeceraItem] = datos[i][index] || ''; // Usar los nombres de la cabecera como claves
            });
            setLocal('%existe', 1);
            return resultado;
        }
    }

    // Si no se encuentra, devolver un objeto JSON con todas las columnas vacías
    const resultado = {};
    cabecera.forEach((cabeceraItem, index) => {
        resultado[cabeceraItem] = ''; // Usar la primera fila (cabecera) como referencia
    });
    return resultado;
}


function obtenerCabecera() {
    if (datos.length > 0 && Array.isArray(datos[0])) {
        return datos[0]; // Devolver la primera sublista como la cabecera
    } else {
        return [];
    }
}

const telefonoABuscar = telefono;
const columnaTelefono = columna;
const resultadoBusqueda = buscarPorTelefonoYColumna(telefonoABuscar, columnaTelefono);

setLocal('%resultado', JSON.stringify(resultadoBusqueda, null, 4));

